"""Impresión de logs con colores y niveles de indentación."""

from rich.console import Console
from rich.text import Text

console = Console(force_jupyter=False, force_terminal=True)
# console = Console()


class Log:
    """Clase para crear logs con diferentes colores y niveles de indentación."""

    def __init__(self, text, color='white', indent=0, upper_case=False):
        """Initialize a Log instance.

        Args:
            text (str): The log message text.
            color (str): The color of the log text. Defaults to 'white'.
            indent (int): The indentation level. Defaults to 0.
            upper_case (bool): Whether to convert the text to uppercase. Defaults to False.
        """
        self.text = text.upper() if upper_case else text
        self.color = color
        self.indent = indent

    def print(self):
        """Print the log message with the specified color and indentation."""
        indent = '  ' * self.indent
        # Construimos un objeto Text con estilo
        txt = Text(indent + self.text, style=self.color)
        # Imprimimos en bloque ANSI, evitando salidas HTML por defecto
        console.print(txt)
